const express = require("express");
const path = require("path");
const multer = require("multer");
const { createProxyMiddleware } = require("http-proxy-middleware");

const app = express();
const PORT = 3100;
const API_BASE = "http://0.0.0.0:9001";

app.use(express.json());
app.use(express.static(path.join(__dirname)));

app.get("/", (req, res) => {
  res.sendFile(path.join(__dirname, "index.html"));
});

// Favicon route - return a simple transparent favicon
app.get("/favicon.ico", (req, res) => {
  const faviconBase64 = "";
  const buf = Buffer.from(faviconBase64, 'base64');
  res.set("Content-Type", "image/x-icon");
  res.set("Content-Length", buf.length);
  res.end(buf);
});

app.get("/api/system", async (req, res) => {
  try {
    const { default: fetch } = await import("node-fetch");
    const r = await fetch(`${API_BASE}/system`);
    const data = await r.json();
    res.json(data);
  } catch (e) {
    res.status(502).json({ error: e.message });
  }
});

app.get("/api/models", async (req, res) => {
  try {
    const { default: fetch } = await import("node-fetch");
    const r = await fetch(`${API_BASE}/models`);
    const data = await r.json();
    res.json(data);
  } catch (e) {
    res.status(502).json({ error: e.message });
  }
});

app.get("/api/voices", async (req, res) => {
  try {
    const { default: fetch } = await import("node-fetch");
    const model_id = req.query.model_id || "";
    const r = await fetch(`${API_BASE}/voices?model_id=${encodeURIComponent(model_id)}`);
    const data = await r.json();
    res.json(data);
  } catch (e) {
    res.status(502).json({ error: e.message });
  }
});

const upload = multer({ storage: multer.memoryStorage() });
app.post("/api/upload", upload.single("file"), async (req, res) => {
  try {
    const { default: fetch } = await import("node-fetch");
    const FormData = (await import("node-fetch")).FormData || require("form-data");
    const form = new (require("form-data"))();
    form.append("file", req.file.buffer, { filename: req.file.originalname, contentType: req.file.mimetype });
    const r = await fetch(`${API_BASE}/upload`, { method: "POST", body: form, headers: form.getHeaders() });
    const data = await r.json();
    res.json(data);
  } catch (e) {
    res.status(502).json({ error: e.message });
  }
});

app.get("/api/synthesize", async (req, res) => {
  try {
    const { default: fetch } = await import("node-fetch");
    const { text, model_id, voice } = req.query;
    
    if (!text || !model_id) {
      console.error("Missing required parameters");
      return res.status(400).json({ error: "Missing required parameters: text, model_id" });
    }
    
    console.log(`[Express] Synthesize request - Model: ${model_id}, Voice: ${voice}, Text length: ${text.length}`);
    
    const url = `${API_BASE}/synthesize?text=${encodeURIComponent(text)}&model_id=${encodeURIComponent(model_id)}&voice=${encodeURIComponent(voice || "default")}`;
    
    const r = await fetch(url, { timeout: 120000 }); // 2 minute timeout
    
    if (!r.ok) {
      let errorBody = "";
      try {
        errorBody = await r.text();
      } catch (e) {
        errorBody = "Could not read error response";
      }
      console.error(`[Express] Backend error ${r.status}: ${errorBody}`);
      return res.status(r.status).json({ error: `Backend error: ${r.status}`, details: errorBody.substring(0, 200) });
    }
    
    const contentType = r.headers.get("content-type");
    if (!contentType || !contentType.includes("audio")) {
      console.error(`[Express] Invalid content-type from backend: ${contentType}`);
      return res.status(502).json({ error: "Backend did not return audio", contentType });
    }
    
    const arrayBuffer = await r.arrayBuffer();
    
    if (!arrayBuffer || arrayBuffer.byteLength === 0) {
      console.error("[Express] Empty audio buffer from backend");
      return res.status(502).json({ error: "Backend returned empty audio" });
    }
    
    const buffer = Buffer.from(arrayBuffer);
    console.log(`[Express] Sending ${buffer.length} bytes of audio to client`);
    res.set("Content-Type", "audio/wav");
    res.set("Content-Length", buffer.length);
    res.end(buffer);
  } catch (e) {
    console.error("[Express] Synthesize error:", e.message);
    res.status(502).json({ error: e.message || "Internal server error" });
  }
});

app.listen(PORT, "0.0.0.0", () => {
  console.log(`cypher-aibook frontend running at http://0.0.0.0:${PORT}`);
});
